const rows = $input.data.rows || [];
const tableRows = rows.map(r => `<tr><td>${r.name}</td><td>${r.email}</td><td>${r.company}</td><td>${r.created_at}</td></tr>`).join('');
return { html: `<table border="1"><thead><tr><th>Name</th><th>Email</th><th>Company</th><th>Date</th></tr></thead><tbody>${tableRows}</tbody></table>`, count: rows.length };
